# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews.
# Category: xss

using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;

namespace ReviewApp.Controllers
{
    public class ReviewsController : Controller
    {
        private static List<Review> reviews = new List<Review>
        {
            new Review { Id = 1, ProductId = 1, ReviewText = "This is a **great** product!", Rating = 5 },
            new Review { Id = 2, ProductId = 1, ReviewText = "_I love this product_!", Rating = 4 }
        };

        public ActionResult Index(int id)
        {
            var reviewsForProduct = reviews.Where(r => r.ProductId == id).ToList();
            return View(reviewsForProduct);
        }

        [HttpPost]
        public ActionResult SubmitReview(Review review)
        {
            if (ModelState.IsValid)
            {
                reviews.Add(review);
                return RedirectToAction("Index", new { id = review.ProductId });
            }
            else
            {
                return View("Error");
            }
        }
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string ReviewText { get; set; }
        public int Rating { get; set; }
    }
}